unitsize(0.4 cm);

pair A, B, C, D, P, V;

A = ((5 + 10)/3, -10);
B = ((5 - 10)/3, 10);
V = (-4,-2);
P = (V + reflect(A,B)*(V))/2;
C = (0,5);
D = (1,2);

draw((-10,0)--(10,0));
draw((0,-10)--(0,10));
draw(A--B,red);
draw(V--P,dashed);
draw(C--V,Arrow(6));
draw(C--D,Arrow(6));

